// Rise 6.0 - TargetHUD reads S04:
if (event.getPacket() instanceof S04PacketEntityEquipment) {
    S04PacketEntityEquipment s04 = (S04PacketEntityEquipment) event.getPacket();
    if (s04.getEntityID() == targetEntityId) {
        int slot = s04.getSlot();
        ItemStack item = s04.getItemStack();
        if (slot == 0) targetWeapon = item;       // held item
        if (slot == 4) targetHelmet = item;        // helmet
        if (slot == 3) targetChestplate = item;    // chestplate
        if (slot == 2) targetLeggings = item;      // leggings
        if (slot == 1) targetBoots = item;         // boots
    }
}
// Vanilla S04PacketEntityEquipment:
public class S04PacketEntityEquipment implements Packet<INetHandlerPlayClient> {
    private int entityId;
    private int slot;
    private ItemStack item;
    public S04PacketEntityEquipment() {}
    public S04PacketEntityEquipment(int idIn, int slotIn, ItemStack itemIn) {
        this.entityId = idIn; this.slot = slotIn; this.item = itemIn == null ? null : itemIn.copy();
    }
    public void processPacket(INetHandlerPlayClient h) { h.handleEntityEquipment(this); }
    public int getEntityID() { return this.entityId; }
    public int getSlot() { return this.slot; }
    public ItemStack getItemStack() { return this.item; }
}
